from typing import List, Optional
from dataclasses import dataclass, field

@dataclass
class ResearchTask:
    """研究任务节点"""
    title: str
    intent: str
    query: str
    subtasks: List['ResearchTask'] = field(default_factory=list)
    summary: Optional[str] = None
    depth: int = 0

def decompose_task(llm, task: ResearchTask, max_depth=3):
    """递归分解研究任务"""
    if task.depth >= max_depth:
        return task
    if is_task_simple(task):
        return task

    prompt = f"""请将以下研究任务分解为子任务：
    任务：{task.title}
    意图：{task.intent}
    返回 JSON 数组：[{{title, intent, query}}]"""

    response = llm.generate(prompt)
    subtasks_data = parse_json(response)

    for item in subtasks_data:
        subtask = ResearchTask(
            title=item['title'],
            intent=item['intent'],
            query=item['query'],
            depth=task.depth + 1
        )
        decomposed = decompose_task(llm, subtask, max_depth)
        task.subtasks.append(decomposed)
    return task

def is_task_simple(task: ResearchTask) -> bool:
    """判断任务是否足够简单"""
    simple_kw = ['定义', '概念', '是什么', 'overview']
    return any(kw in task.title.lower() for kw in simple_kw)

def build_task_tree(topic: str, llm, max_depth=3):
    root = ResearchTask(
        title=topic,
        intent=f"全面研究{topic}",
        query=topic, depth=0
    )
    return decompose_task(llm, root, max_depth)

def count_tasks(task: ResearchTask) -> int:
    count = 1
    for sub in task.subtasks:
        count += count_tasks(sub)
    return count

# 使用示例
task_tree = build_task_tree(
    "多模态大模型的最新进展", llm, max_depth=3
)
print(f"总任务数: {count_tasks(task_tree)}")
